package com.example.springboot.controller;

import com.example.springboot.common.PageResult;
import com.example.springboot.entity.Word;
import com.example.springboot.service.WordService;
import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import javax.annotation.Resource;
import java.util.List;


@RestController
@RequestMapping("/words")
public class WordController {

    @Resource
    private WordService wordService;

    @PostMapping
    public int addWord(@RequestBody Word word) {
        return wordService.addWord(word);
    }

    @PutMapping
    public int updateWord(@RequestBody Word word) {
        return wordService.updateWord(word);
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<String> deleteWord(@PathVariable int id) {
        try {
            int result = wordService.deleteWord(id);
            if (result > 0) {
                return ResponseEntity.ok("删除成功");
            } else {
                return ResponseEntity.status(HttpStatus.NOT_FOUND).body("未找到该单词");
            }
        } catch (DataIntegrityViolationException e) {
            // 捕获外键约束异常，提示不能删除
            return ResponseEntity.status(HttpStatus.CONFLICT).body("删除失败：该单词被使用，无法删除");
        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body("删除失败");
        }
    }


    @GetMapping("/{id}")
    public Word getWordById(@PathVariable int id) {
        return wordService.getWordById(id);
    }

    @GetMapping("/search")
    public List<Word> searchWords(@RequestParam String keyword) {
        return wordService.searchWords(keyword);
    }


    @GetMapping
    public PageResult<Word> getAllWords(
            @RequestParam(defaultValue = "1") int pageNum,
            @RequestParam(defaultValue = "10") int pageSize,
            @RequestParam(required = false) String keyword) {

        PageResult<Word> pageResult;
        if (keyword != null && !keyword.trim().isEmpty()) {
            pageResult = wordService.searchWordsPaged(keyword, pageNum, pageSize);
        } else {
            pageResult = wordService.getAllWordsPaged(pageNum, pageSize);
        }
        return pageResult;
    }


}
package com.example.springboot.controller;

import com.alibaba.excel.EasyExcel;
import com.example.springboot.dto.WordExcelDTO;
import com.example.springboot.entity.Word;
import com.example.springboot.service.WordService;
import jakarta.annotation.Resource;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;


import jakarta.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.util.List;
import java.util.stream.Collectors;

@RestController
@RequestMapping("/word-excel")
public class WordExcelController {

    @Resource
    private WordService wordService;

    // ✅ 导入 Excel
    @PostMapping("/import")
    public String importExcel(@RequestParam("file") MultipartFile file) throws IOException {
        List<WordExcelDTO> data = EasyExcel.read(file.getInputStream())
                .head(WordExcelDTO.class)
                .sheet()
                .doReadSync();

        List<Word> words = data.stream().map(dto -> {
            Word word = new Word();
            word.setWord(dto.getWord());
            word.setDefinition(dto.getDefinition());
            word.setPronunciation(dto.getPronunciation());
            word.setCustomContent(dto.getCustomContent());
            return word;
        }).collect(Collectors.toList());

        for (Word word : words) {
            wordService.addWord(word);
        }

        return "导入成功：" + words.size() + " 条";
    }

    @GetMapping(value = "/export", produces = "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")
    public void exportExcel(HttpServletResponse response) {
        try {
            List<Word> words = wordService.getAllWords();
            List<WordExcelDTO> data = words.stream().map(word -> {
                WordExcelDTO dto = new WordExcelDTO();
                dto.setWord(word.getWord());
                dto.setDefinition(word.getDefinition());
                dto.setPronunciation(word.getPronunciation());
                dto.setCustomContent(word.getCustomContent());
                return dto;
            }).collect(Collectors.toList());

            response.setContentType("application/vnd.openxmlformats-officedocument.spreadsheetml.sheet");
            response.setCharacterEncoding("utf-8");
            String fileName = URLEncoder.encode("单词表", StandardCharsets.UTF_8.toString()).replaceAll("\\+", "%20");
            response.setHeader("Content-Disposition", "attachment;filename*=utf-8''" + fileName + ".xlsx");

            EasyExcel.write(response.getOutputStream(), WordExcelDTO.class)
                    .sheet("单词")
                    .doWrite(data);

        } catch (Exception e) {
            e.printStackTrace();
            throw new RuntimeException("导出Excel失败", e);
        }
    }

    @GetMapping("/export-test")
    public void exportTest(HttpServletResponse response) throws IOException {
        response.setContentType("text/plain");
        response.getWriter().write("Hello Export Test");
    }

    @PostMapping(value = "/export-selected", produces = "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")
    public void exportSelectedWords(@RequestBody List<Integer> ids, HttpServletResponse response) {
        try {
            // 根据 ID 查询选中的单词
            List<Word> words = wordService.getWordsByIds(ids);

            // 转换为 Excel DTO
            List<WordExcelDTO> data = words.stream().map(word -> {
                WordExcelDTO dto = new WordExcelDTO();
                dto.setWord(word.getWord());
                dto.setDefinition(word.getDefinition());
                dto.setPronunciation(word.getPronunciation());
                dto.setCustomContent(word.getCustomContent());
                return dto;
            }).collect(Collectors.toList());

            // 设置响应头
            response.setContentType("application/vnd.openxmlformats-officedocument.spreadsheetml.sheet");
            response.setCharacterEncoding("utf-8");
            String fileName = URLEncoder.encode("选中单词表", StandardCharsets.UTF_8.toString()).replaceAll("\\+", "%20");
            response.setHeader("Content-Disposition", "attachment;filename*=utf-8''" + fileName + ".xlsx");

            // 写入 Excel
            EasyExcel.write(response.getOutputStream(), WordExcelDTO.class)
                    .sheet("选中单词")
                    .doWrite(data);

        } catch (Exception e) {
            e.printStackTrace();
            throw new RuntimeException("导出选中单词失败", e);
        }
    }




}
