<script setup>
import { ref, reactive, onMounted } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import axios from 'axios'

const vocabulary = reactive({ name: '' })
const tableData = ref([])
const total = ref(0)
const pageSize = ref(10)
const currentPage = ref(1)
const dialogVisible = ref(false)
const form = reactive({ id: null, word: '', definition: '', customContent: '' })

// 跨页选中 id 集合（Set 更高效去重）
const selectedIds = ref(new Set())

// 获取单词列表
const fetchWords = async () => {
  try {
    const params = {
      pageNum: currentPage.value,
      pageSize: pageSize.value,
      keyword: vocabulary.name || undefined
    }
    const res = await axios.get('http://localhost:8080/words', { params })
    tableData.value = res.data.records
    total.value = res.data.total
  } catch (err) {
    ElMessage.error('获取单词列表失败')
  }
}

// 重置查询，同时清空选中
const reset = () => {
  vocabulary.name = ''
  currentPage.value = 1
  selectedIds.value.clear()
  fetchWords()
}

// 发音（Web Speech API）
const playWord = (text) => {
  const utterance = new SpeechSynthesisUtterance(text)
  utterance.lang = 'en-US'
  window.speechSynthesis.speak(utterance)
}

// 新增或编辑弹窗
const openDialog = (row = null) => {
  if (row) {
    Object.assign(form, row)
  } else {
    Object.assign(form, { id: null, word: '', definition: '', customContent: '' })
  }
  dialogVisible.value = true
}

// 提交新增或编辑
const submitForm = async () => {
  try {
    if (form.id) {
      await axios.put('http://localhost:8080/words', form)
      ElMessage.success('更新成功')
    } else {
      await axios.post('http://localhost:8080/words', form)
      ElMessage.success('新增成功')
    }
    dialogVisible.value = false
    fetchWords()
  } catch (err) {
    ElMessage.error('提交失败')
  }
}

// 删除单词
const handleDelete = async (id) => {
  try {
    await ElMessageBox.confirm('确定删除该单词？', '提示', { type: 'warning' })
    await axios.delete(`http://localhost:8080/words/${id}`)
    ElMessage.success('删除成功')
    selectedIds.value.delete(id)
    fetchWords()
  } catch (err) {
    if (err !== 'cancel') {
      const word = tableData.value.find(item => item.id === id)?.word || `ID ${id}`
      if (err.response && err.response.data) {
        ElMessage.error(`单词「${word}」删除失败：${err.response.data}`)
      } else {
        ElMessage.error(`单词「${word}」删除失败`)
      }
    }
  }
}


// 批量删除
const handleBatchDelete = async () => {
  if (selectedIds.value.size === 0) {
    ElMessage.warning('请先选择要删除的单词')
    return
  }

  try {
    await ElMessageBox.confirm('确定批量删除选中项？', '提示', { type: 'warning' })

    const ids = Array.from(selectedIds.value)
    const failed = [] // 保存删除失败的单词

    for (const id of ids) {
      try {
        await axios.delete(`http://localhost:8080/words/${id}`)
        selectedIds.value.delete(id)
      } catch (err) {
        const word = tableData.value.find(item => item.id === id)?.word || `ID ${id}`
        failed.push(word)
      }
    }

    if (failed.length === 0) {
      ElMessage.success('批量删除成功')
    } else {
      ElMessage.warning(`以下单词删除失败（可能是用户添加的，禁止删除）：${failed.join('、')}`)
    }

    fetchWords()
  } catch (err) {
    if (err !== 'cancel') {
      ElMessage.error('批量删除中发生错误')
    }
  }
}



// 获取当前页默认选中行，用于表格选中回显
const getSelectedRows = () => {
  return tableData.value.filter(item => selectedIds.value.has(item.id))
}

// 选中项变化，更新跨页选中id集合
const handleSelectionChange = (selection) => {
  // 先移除当前页所有id
  tableData.value.forEach(item => selectedIds.value.delete(item.id))
  // 添加当前页选中的id
  selection.forEach(item => selectedIds.value.add(item.id))
}

// 导出 Excel（支持跨页选中）
const handleExport = async () => {
  try {
    if (selectedIds.value.size === 0) {
      // 无选中，导出所有
      window.open('http://localhost:8080/word-excel/export')
    } else {
      // 有选中，导出选中id
      const ids = Array.from(selectedIds.value)
      const res = await axios.post('http://localhost:8080/word-excel/export-selected', ids, {
        responseType: 'blob'
      })
      const blob = new Blob([res.data], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' })
      const url = window.URL.createObjectURL(blob)
      const link = document.createElement('a')
      link.href = url
      link.download = '选中单词表.xlsx'
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      window.URL.revokeObjectURL(url)
      ElMessage.success('导出成功')
    }
  } catch (err) {
    ElMessage.error('导出失败')
  }
}

// 导入成功提示
const handleImportSuccess = () => {
  ElMessage.success('导入成功')
  fetchWords()
}

// 分页大小改变
const handleSizeChange = (val) => {
  pageSize.value = val
  currentPage.value = 1
  fetchWords()
}

// 当前页改变
const handleCurrentChange = (val) => {
  currentPage.value = val
  fetchWords()
}
//  页面加载时获取单词列表
onMounted(() => {
  fetchWords()
})
</script>
