<script setup>
import { ref, reactive, onMounted, nextTick } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import axios from 'axios'

// 用户 ID
const userId = localStorage.getItem('userId')

// 表格相关
const vocabulary = reactive({ name: '' })
const tableData = ref([])
const total = ref(0)
const pageSize = ref(10)
const currentPage = ref(1)
const selectedIds = ref(new Set())
const tableRef = ref(null)

// 今日计划相关
const todayPlanDialogVisible = ref(false)
const todayPlanWords = ref([])
const selectedTodayWords = ref([])
const todayPlanTotal = ref(0)
const todayPlanCurrentPage = ref(1)
const todayPlanWordIds = ref(new Set()) // ✅ 新增：保存已加入计划的单词 ID

// 判断某行是否可选中
const isSelectable = (row) => {
  return !todayPlanWordIds.value.has(row.id)
}




// 获取单词数据
const fetchWords = async () => {
  try {
    const params = {
      pageNum: currentPage.value,
      pageSize: pageSize.value,
      keyword: vocabulary.name || undefined
    }
    const res = await axios.get('http://localhost:8080/words', { params })
    tableData.value = res.data.records
    total.value = res.data.total

    await nextTick()
    restoreSelection()
  } catch (err) {
    ElMessage.error('获取单词列表失败')
  }
}

// 多选变化
const handleSelectionChange = (selection) => {
  selection.forEach(item => selectedIds.value.add(item.id))
  tableData.value.forEach(row => {
    if (!selection.find(s => s.id === row.id)) {
      selectedIds.value.delete(row.id)
    }
  })
}

// 恢复勾选状态
const restoreSelection = () => {
  if (!tableRef.value) return
  tableRef.value.clearSelection()
  tableData.value.forEach(row => {
    if (selectedIds.value.has(row.id)) {
      tableRef.value.toggleRowSelection(row, true)
    }
  })
}

// 重置查询
const reset = () => {
  vocabulary.name = ''
  currentPage.value = 1
  fetchWords()
}

// 分页
const handleSizeChange = (val) => {
  pageSize.value = val
  currentPage.value = 1
  fetchWords()
}
const handleCurrentChange = (val) => {
  currentPage.value = val
  fetchWords()
}

// 发音
const playWord = (text) => {
  if (!text) {
    ElMessage.warning('无效的单词发音')
    return
  }
  const utterance = new SpeechSynthesisUtterance(text)
  utterance.lang = 'en-US'
  window.speechSynthesis.speak(utterance)
}

// 加入背诵计划
const addSelectedWordsToPlan = async () => {
  if (!selectedIds.value.size) {
    ElMessage.warning('请先选择单词')
    return
  }
  try {
    const wordIds = Array.from(selectedIds.value)
    await axios.post('http://localhost:8080/today-plan/add', {
      userId,
      wordIds
    })

    ElMessage.success('单词已加入背诵计划')
    if (todayPlanDialogVisible.value) {
      loadTodayPlan(todayPlanCurrentPage.value)
    }

    // 重新加载已加入计划的 ID，刷新禁选状态
    await loadTodayPlan()
    fetchWords()

  } catch (err) {
    if (err.response && err.response.status === 409) {
      const data = err.response.data || {}
      const existingIds = data.existingWordIds || []

      // 你可以根据已有单词ID在tableData中找到对应的单词, 拼接提示内容
      const existingWords = tableData.value
          .filter(item => existingIds.includes(item.id))
          .map(item => item.word)
          .join('，')

      ElMessage.warning(`部分单词已存在长期记忆，请不要重复添加: ${existingWords}`)

      // 仍然刷新接口，保持界面状态
      if (todayPlanDialogVisible.value) {
        await loadTodayPlan(todayPlanCurrentPage.value)
      }
      await loadTodayPlan()
      fetchWords()
    } else {
      ElMessage.error('加入背诵计划失败')
    }
  }
}

// 打开今日计划弹窗
const openTodayPlanDialog = () => {
  todayPlanDialogVisible.value = true
  loadTodayPlan()
}

// 加载今日计划
const loadTodayPlan = async () => {
  try {
    const res = await axios.get('http://localhost:8080/today-plan/todaylist', {
      params: { userId }
    })

    todayPlanWords.value = res.data
    todayPlanTotal.value = res.data.length
    todayPlanWordIds.value = new Set(res.data.map(item => item.wordId || item.id)) // ✅ 更新禁选 ID 集合

  } catch (err) {
    ElMessage.error('加载今日背诵单词失败')
  }
}

// 今日计划选择
const handleTodaySelectionChange = (val) => {
  selectedTodayWords.value = val
}

// 导出选中
const exportSelectedTodayWords = async () => {
  if (!selectedTodayWords.value.length) {
    ElMessage.warning('请先选择单词')
    return
  }
  try {
    const selectedIds = selectedTodayWords.value.map(item => item.id)
    const params = new URLSearchParams()
    params.append('userId', userId)
    selectedIds.forEach(id => params.append('ids', id))

    const res = await axios.get('http://localhost:8080/plan-excel/export-selected', {
      params,
      paramsSerializer: params => params.toString(),
      responseType: 'blob'
    })

    const blob = new Blob([res.data], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' })
    const url = window.URL.createObjectURL(blob)
    const link = document.createElement('a')
    link.href = url
    link.setAttribute('download', 'today_words.xlsx')
    document.body.appendChild(link)
    link.click()
    document.body.removeChild(link)
    window.URL.revokeObjectURL(url)

  } catch (err) {
    ElMessage.error('导出失败')
  }
}

// 删除今日单词
const deleteSelectedTodayWords = async () => {
  if (!selectedTodayWords.value.length) {
    ElMessage.warning('请先选择要删除的单词')
    return
  }

  try {
    const confirm = await ElMessageBox.confirm(
        '确定要从今日背诵计划中删除选中的单词吗？',
        '提示',
        {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        }
    )

    const idsToDelete = selectedTodayWords.value.map(item => item.id)

    await axios.post('http://localhost:8080/today-plan/delete', {
      userId,
      wordIds: idsToDelete
    })

    ElMessage.success('删除成功')
    loadTodayPlan()

  } catch (err) {
    if (err !== 'cancel') {
      ElMessage.error('删除失败')
    }
  }
}

// 初始化加载
onMounted(async () => {
  await loadTodayPlan()
  fetchWords()
})
</script>

package com.example.springboot.controller;

import com.example.springboot.dto.AddWordsRequest;
import com.example.springboot.entity.TodayPlan;
import com.example.springboot.service.TodayPlanService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import javax.annotation.Resource;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/today-plan")
public class TodayPlanController {

    @Resource
    private TodayPlanService todayPlanService;

    @PostMapping("/add")
    public ResponseEntity<?> addWordsToPlan(@RequestBody AddWordsRequest request) {
        List<Integer> existingWordIds = todayPlanService.addWordsToPlan(request.getUserId(), request.getWordIds());
        if (existingWordIds == null || existingWordIds.isEmpty()) {
            return ResponseEntity.ok(Map.of("message", "单词已全部成功加入背诵计划"));
        } else {
            return ResponseEntity.status(409).body(Map.of(
                    "message", "部分单词已存在长期记忆，请不要重复添加",
                    "existingWordIds", existingWordIds
            ));
        }
    }

    //  获取今日计划
    @GetMapping("/todaylist")
    public List<TodayPlan> getTodayPlan(@RequestParam Integer userId) {
        return todayPlanService.getTodayPlan(userId);
    }

    @PostMapping("/delete")
    public void deleteWordsFromPlan(@RequestBody AddWordsRequest request) {
        todayPlanService.deletePlansByIds(request.getUserId(), request.getWordIds());
    }
}
package com.example.springboot.controller;

import com.alibaba.excel.EasyExcel;
import com.example.springboot.dto.WordExcelDTO;
import com.example.springboot.entity.TodayPlan;
import com.example.springboot.service.TodayPlanService;
import jakarta.annotation.Resource;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.web.bind.annotation.*;

import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.util.List;
import java.util.stream.Collectors;

@RestController
@RequestMapping("/plan-excel")
public class TodayPlanExcelController {

    @Resource
    private TodayPlanService todayPlanService;

    @GetMapping(value = "/export-selected", produces = "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")
    public void exportSelectedPlanExcel(@RequestParam Integer userId,
                                        @RequestParam List<Integer> ids,
                                        HttpServletResponse response) {
        try {
            List<TodayPlan> planList = todayPlanService.exportPlanByIds(userId, ids);
            List<WordExcelDTO> exportData = planList.stream().map(plan -> {
                WordExcelDTO dto = new WordExcelDTO();
                dto.setWord(plan.getWordText());
                dto.setDefinition(plan.getMeaning());
                dto.setPronunciation("");
                dto.setCustomContent("");
                return dto;
            }).collect(Collectors.toList());

            String fileName = URLEncoder.encode("选中背诵计划", StandardCharsets.UTF_8).replaceAll("\\+", "%20");
            response.setContentType("application/vnd.openxmlformats-officedocument.spreadsheetml.sheet");
            response.setCharacterEncoding("utf-8");
            response.setHeader("Content-Disposition", "attachment;filename*=utf-8''" + fileName + ".xlsx");

            EasyExcel.write(response.getOutputStream(), WordExcelDTO.class)
                    .sheet("选中背诵计划")
                    .doWrite(exportData);

        } catch (Exception e) {
            throw new RuntimeException("导出选中计划失败", e);
        }
    }

}
