package com.example.springboot.service;

import com.example.springboot.entity.TodayPlan;
import com.example.springboot.mapper.LongTermMemoryMapper;
import com.example.springboot.mapper.TodayPlanMapper;
import org.springframework.stereotype.Service;

import javax.annotation.Resource;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class TodayPlanService {

    @Resource
    private TodayPlanMapper todayPlanMapper;

    @Resource
    private LongTermMemoryMapper longTermMemoryMapper;

    /**
     * 添加单词到今日计划，自动过滤已存在于user_word_plan或long_term_memory的单词
     * @param userId 用户ID
     * @param wordIds 待添加单词ID列表
     * @return 已存在的单词ID列表
     */
    public List<Integer> addWordsToPlan(Integer userId, List<Integer> wordIds) {
        // 查询今天计划和长期记忆中已存在的单词ID
        List<Integer> existingInPlan = todayPlanMapper.selectExistingWordIds(userId, wordIds);
        List<Integer> existingInLtm = longTermMemoryMapper.selectExistingWordIds(userId, wordIds);

        Set<Integer> existingSet = new HashSet<>();
        if (existingInPlan != null) existingSet.addAll(existingInPlan);
        if (existingInLtm != null) existingSet.addAll(existingInLtm);

        // 过滤要插入的单词ID
        List<Integer> toAdd = wordIds.stream()
                .filter(id -> !existingSet.contains(id))
                .collect(Collectors.toList());

        if (!toAdd.isEmpty()) {
            todayPlanMapper.batchInsertPlans(userId, toAdd);
        }

        // 返回已存在的单词ID给前端做提示
        return new ArrayList<>(existingSet);
    }

    public List<TodayPlan> getTodayPlan(Integer userId) {
        return todayPlanMapper.getTodayPlans(userId);
    }

    public List<TodayPlan> exportPlanByIds(Integer userId, List<Integer> ids) {
        return todayPlanMapper.selectPlansByIds(userId, ids);
    }

    public void deletePlansByIds(Integer userId, List<Integer> ids) {
        todayPlanMapper.deletePlansByIds(userId, ids);
    }
}
