<!DOCTYPE mapper
        PUBLIC "-//mybatis.org//DTD Mapper 3.0//EN"
        "http://mybatis.org/dtd/mybatis-3-mapper.dtd">

<mapper namespace="com.example.springboot.mapper.LongTermMemoryMapper">

    <insert id="insertLongTermMemory" parameterType="com.example.springboot.entity.LongTermMemory" useGeneratedKeys="true" keyProperty="id">
        INSERT INTO long_term_memory(
            user_id, word_id, review_count, pass_count, interval_days,
            next_review_date, last_review_date,
            longmemory_score, longmemory_seen, created_at, updated_at
        )
        VALUES(
                  #{userId}, #{wordId}, #{reviewCount}, #{passCount}, #{intervalDays},
                  #{nextReviewDate}, #{lastReviewDate},
                  #{longmemoryScore}, #{longmemorySeen}, NOW(), NOW()
              )
    </insert>

    <select id="selectExistingWordIds" resultType="int" parameterType="map">
        SELECT word_id
        FROM long_term_memory
        WHERE user_id = #{userId}
        AND word_id IN
        <foreach collection="wordIds" item="wordId" open="(" separator="," close=")">
            #{wordId}
        </foreach>
    </select>

    <select id="selectDueReviews" resultType="com.example.springboot.dto.LongTermMemoryWithWord" parameterType="map">
        SELECT ltm.*, w.word, w.definition
        FROM long_term_memory ltm
        LEFT JOIN words w ON ltm.word_id = w.id
        WHERE ltm.user_id = #{userId}
        <if test="longmemorySeenList != null and longmemorySeenList.size() > 0">
            AND ltm.longmemory_seen IN
            <foreach collection="longmemorySeenList" item="item" open="(" separator="," close=")">
                #{item}
            </foreach>
        </if>
        AND ltm.next_review_date &lt;= #{now}
        ORDER BY
        CASE
        WHEN ltm.longmemory_seen = 0 THEN 1
        WHEN ltm.longmemory_seen = 1 THEN 2
        WHEN ltm.longmemory_seen = 2 THEN 3
        WHEN ltm.longmemory_seen = 3 THEN 4
        WHEN ltm.longmemory_seen = 4 THEN 5
        WHEN ltm.longmemory_seen = 5 THEN 6
        ELSE 7
        END ASC,
        ltm.next_review_date ASC,
        ltm.last_review_date ASC
        LIMIT #{offset}, #{size}
    </select>

    <update id="updateLongTermMemory" parameterType="com.example.springboot.entity.LongTermMemory">
        UPDATE long_term_memory
        SET review_count = #{reviewCount},
            pass_count = #{passCount},
            interval_days = #{intervalDays},
            next_review_date = #{nextReviewDate},
            last_review_date = #{lastReviewDate},
            longmemory_score = #{longmemoryScore},
            longmemory_seen = #{longmemorySeen},
            updated_at = NOW()
        WHERE id = #{id}
    </update>

    <select id="selectById" resultType="com.example.springboot.entity.LongTermMemory" parameterType="int">
        SELECT *
        FROM long_term_memory
        WHERE id = #{id}
    </select>

</mapper>
