            return ResponseEntity.status(HttpStatus.CONFLICT).body("所有单词已存在，无需再添加");
        }
        return ResponseEntity.ok("成功添加 " + insertedCount + " 个新单词");
    }

    // 获取已选短期记忆单词
    @GetMapping("/select-words")
    public ResponseEntity<?> getSelectedWords(@RequestParam(value = "userId") Integer userId) {
        if (userId == null) {
