@RestController
@RequestMapping("/feedback")
public class FeedbackController {

    private final FeedbackService feedbackService;

    @Autowired
    public FeedbackController(FeedbackService feedbackService) {
        this.feedbackService = feedbackService;
    }

    /**
     * 用户提交反馈
     */
    @PostMapping("/user/add")
    public String addFeedback(@RequestBody Feedback feedback, @RequestParam Integer userId) {
        System.out.println("POST /user/add -> userId = " + userId);
        if (userId == null || userId <= 0) {
            return "请先登录";
        }
        feedback.setUserId(userId);
        int result = feedbackService.addFeedback(feedback);
        return result > 0 ? "反馈提交成功" : "反馈提交失败";
    }

    @GetMapping("/user/list")
    public List<Feedback> getUserFeedback(@RequestParam Integer userId) {
        System.out.println("GET /user/list -> userId = " + userId);
        if (userId == null || userId <= 0) {
            return null;
        }
        return feedbackService.getFeedbackByUser(userId);
    }

    @DeleteMapping("/user/delete/{id}")
    public String deleteUserFeedback(@PathVariable Integer id, @RequestParam Integer userId) {
        System.out.println("DELETE /user/delete/" + id + " -> userId = " + userId);
        if (userId == null || userId <= 0) {
            return "请先登录";
        }
        Feedback feedback = feedbackService.getFeedbackById(id);
        if (feedback == null || !feedback.getUserId().equals(userId)) {
            return "删除失败，可能不是您的反馈或不存在";
        }
        int result = feedbackService.deleteFeedback(id, userId);
        return result > 0 ? "删除成功" : "删除失败";
    }

