     * 管理员查询所有反馈接口
     * 不需要传 userId，且不做权限验证，直接返回所有反馈
     */
    @GetMapping("/list/all")
    public List<Feedback> getAllFeedback() {
        System.out.println("GET /list/all 请求到达");
        return feedbackService.getAllFeedback();
    }
