<script setup>
import { ref, reactive, onMounted } from 'vue'
import axios from 'axios'
import { ElMessage } from 'element-plus'

// 反馈数组
const feedbacks = ref([])

// 对展开行对应的回复输入框绑定内容，key为反馈id，value为输入内容
const replyMap = reactive({})

// 当前正在加载状态
const loading = ref(false)

// 当前展开行id列表
const expandedRows = ref([])

// 获取所有反馈（管理员）
const fetchAllFeedback = async () => {
  loading.value = true
  try {
    const res = await axios.get('http://localhost:8080/feedback/list/all')
    if (Array.isArray(res.data)) {
      feedbacks.value = res.data
      res.data.forEach((item) => {
        replyMap[item.id] = item.reply || ''
      })
    } else {
      feedbacks.value = []
      ElMessage.error('获取反馈列表失败，数据格式不正确')
    }
  } catch (error) {
    console.error(error)
    ElMessage.error('获取反馈失败')
  } finally {
    loading.value = false
  }
}

// 提交管理员回复
const submitReply = async (id) => {
  const replyContent = replyMap[id]?.trim()
  if (!replyContent) {
    ElMessage.warning('回复内容不能为空')
    return
  }
  try {
    await axios.put(`http://localhost:8080/feedback/reply/${id}`, {
      reply: replyContent,
    })
    ElMessage.success('回复提交成功')
    // 刷新列表并更新replyMap
    await fetchAllFeedback()
    // 保持当前展开状态
    if (!expandedRows.value.includes(id)) {
      expandedRows.value.push(id)
    }
  } catch (error) {
    console.error(error)
    ElMessage.error('回复提交失败')
  }
}

// 展开事件，用于保持 expandedRows 中的内容
const handleExpand = (row, expanded) => {
  if (expanded) {
    if (!expandedRows.value.includes(row.id)) {
      expandedRows.value.push(row.id)
    }
  } else {
    const idx = expandedRows.value.indexOf(row.id)
    if (idx >= 0) {
      expandedRows.value.splice(idx, 1)
    }
  }
}

// 页面加载时，获取所有反馈
onMounted(() => {
  fetchAllFeedback()
})
</script>

